+#!/usr/bin/env python3
+# -*- coding: utf-8 -*-
+"""Generate a single-file AI HOT morning-briefing dashboard from the daily report JSON.
+Fully static HTML (CSS-only), no JS dependency, no external resources."""
+import json, os, html, datetime as _dt
+
+BASE = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
+DATA = os.path.join(BASE, "data", "today.json")
+OUT = os.path.join(BASE, "ai-hot-daily-2026-07-23.html")
+
+# 5 fixed sections in required order
+FIXED = ["模型发布/更新", "产品发布/更新", "行业动态", "论文研究", "技巧与观点"]
+COLORS = {
+    "模型发布/更新": "#3b82f6",
+    "产品发布/更新": "#8b5cf6",
+    "行业动态": "#10b981",
+    "论文研究": "#f59e0b",
+    "技巧与观点": "#ec4899",
+}
+
+d = json.load(open(DATA, encoding="utf-8"))
+report_date = d.get("date")
+window_start = d.get("windowStart")
+window_end = d.get("windowEnd")
+
+WD = ["周一", "周二", "周三", "周四", "周五", "周六", "周日"]
+def _parse(iso):
+    return _dt.datetime.strptime(iso[:10], "%Y-%m-%d").date()
+def human_report(iso):
+    dt = _parse(iso); return f"{dt.year}年{dt.month}月{dt.day}日 {WD[dt.weekday()]}"
+def short(iso):
+    dt = _parse(iso); return f"{dt.month}月{dt.day}日"
+report_human = human_report(report_date)
+window_label = f"{short(window_start)} – {short(window_end)}"
+
+by_label = {s["label"]: s.get("items", []) for s in d.get("sections", [])}
+
+sections = []
+counter = 0
+for label in FIXED:
+    items = by_label.get(label, [])
+    norm = []
+    for it in items:
+        counter += 1
+        norm.append({
+            "idx": counter,
+            "title": (it.get("title") or "").strip(),
+            "summary": (it.get("summary") or "").strip(),
+            "source": (it.get("sourceName") or "").strip(),
+            "url": (it.get("sourceUrl") or "").strip(),
+        })
+    sections.append({"label": label, "items": norm})
+total = counter
+
+def clip(text, max=60):
+    arr = list(text)
+    if len(arr) <= max:
+        return text
+    return "".join(arr[:max - 1]) + "…"
+
+def e(text):
+    return html.escape(str(text), quote=True)
+
+# ---- Hero stats ----
+hero_stats = ""
+for s in sections:
+    c = COLORS[s["label"]]
+    hero_stats += (
+        f'<div class="stat" style="background:{c};border-color:{c};opacity:.92">'
+        f'<div class="n">{len(s["items"])}</div><div class="l">{e(s["label"])}</div></div>'
+    )
+
+# ---- Nav ----
+nav = ""
+for i, s in enumerate(sections):
+    c = COLORS[s["label"]]
+    nav += (
+        f'<a href="#sec-{i}"><span class="dot" style="background:{c}"></span>'
+        f'{e(s["label"])}<span class="cnt">{len(s["items"])}</span></a>'
+    )
+
+# ---- Sections + cards ----
+main = ""
+for i, s in enumerate(sections):
+    c = COLORS[s["label"]]
+    head = (
+        f'<div class="section-head"><span class="bar" style="background:{c}"></span>'
+        f'<h2>{e(s["label"])}</h2><span class="badge">{len(s["items"])} 条</span></div>'
+    )
+    if not s["items"]:
+        body = '<div class="empty">本期暂无该版块相关条目</div>'
+    else:
+        cards = ""
+        for it in s["items"]:
+            url = it["url"] or "#"
+            chip = f'<span class="chip">{e(it["source"])}</span>' if it["source"] else ""
+            cards += (
+                '<article class="card">'
+                f'<span class="topaccent" style="background:{c}"></span>'
+                f'<span class="num">{it["idx"]}</span>'
+                f'<h3 class="title">{e(it["title"])}</h3>'
+                f'{chip}'
+                f'<p class="summary">{e(clip(it["summary"], 60))}</p>'
+                f'<a class="link" href="{e(url)}" target="_blank" rel="noopener noreferrer">阅读原文 →</a>'
+                '</article>'
+            )
+        body = f'<div class="grid">{cards}</div>'
+    main += f'<section class="section" id="sec-{i}">{head}{body}</section>'
+
+footer = (
+    f'本期共收录 <b>{total}</b> 条 AI 动态 · 数据来源 '
+    f'<a href="https://aihot.virxact.com" target="_blank" rel="noopener noreferrer">aihot.virxact.com</a>'
+)
+
+HTML = f"""<!DOCTYPE html>
+<html lang="zh-CN">
+<head>
+<meta charset="UTF-8">
+<meta name="viewport" content="width=device-width, initial-scale=1.0">
+<title>AI HOT 日报 · 晨报仪表盘 · {e(report_human)}</title>
+<style>
+  :root{{
+    --bg:#f4f6fb; --card:#ffffff; --ink:#1f2430; --muted:#6b7280;
+    --line:#e7eaf1; --hero1:#6366f1; --hero2:#8b5cf6;
+  }}
+  *{{box-sizing:border-box;}}
+  html{{scroll-behavior:smooth;}}
+  body{{
+    margin:0; background:var(--bg); color:var(--ink);
+    font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","PingFang SC","Microsoft YaHei",sans-serif;
+    line-height:1.6; -webkit-font-smoothing:antialiased;
+  }}
+  a{{color:inherit;}}
+
+  .hero{{
+    background:linear-gradient(135deg,var(--hero1),var(--hero2));
+    color:#fff; padding:46px 24px 40px; text-align:center;
+  }}
+  .hero .kicker{{font-size:13px; letter-spacing:.18em; opacity:.85; text-transform:uppercase;}}
+  .hero h1{{margin:8px 0 4px; font-size:30px; font-weight:800; letter-spacing:.02em;}}
+  .hero .dateline{{font-size:15px; opacity:.92; margin-bottom:18px;}}
+  .hero .total{{
+    display:inline-block; background:rgba(255,255,255,.18); border:1px solid rgba(255,255,255,.35);
+    padding:6px 16px; border-radius:999px; font-size:14px; margin-bottom:24px;
+  }}
+  .hero .total b{{font-size:18px;}}
+  .stats{{display:flex; flex-wrap:wrap; gap:12px; justify-content:center; max-width:880px; margin:0 auto;}}
+  .stat{{border-radius:14px; padding:12px 18px; min-width:120px;}}
+  .stat .n{{font-size:24px; font-weight:800; line-height:1.1;}}
+  .stat .l{{font-size:12.5px; opacity:.95; margin-top:2px;}}
+
+  .nav{{
+    position:sticky; top:0; z-index:20; background:rgba(255,255,255,.92);
+    backdrop-filter:saturate(160%) blur(10px); border-bottom:1px solid var(--line);
+    display:flex; flex-wrap:wrap; gap:8px; justify-content:center; padding:12px 16px;
+  }}
+  .nav a{{
+    text-decoration:none; font-size:13.5px; color:var(--ink); padding:7px 14px;
+    border:1px solid var(--line); border-radius:999px; background:#fff; transition:.15s;
+    display:inline-flex; align-items:center; gap:6px;
+  }}
+  .nav a:hover{{border-color:var(--hero1); color:var(--hero1);}}
+  .nav a .dot{{width:9px; height:9px; border-radius:50%;}}
+  .nav a .cnt{{font-size:11.5px; color:var(--muted); background:var(--bg); border-radius:999px; padding:1px 7px;}}
+
+  .wrap{{max-width:1180px; margin:0 auto; padding:32px 20px 60px;}}
+  .section{{margin-bottom:42px; scroll-margin-top:64px;}}
+  .section-head{{
+    display:flex; align-items:center; gap:12px; margin:0 0 18px;
+    padding-bottom:10px; border-bottom:2px solid var(--line);
+  }}
+  .section-head .bar{{width:5px; height:26px; border-radius:3px;}}
+  .section-head h2{{font-size:20px; margin:0; font-weight:800;}}
+  .section-head .badge{{margin-left:auto; font-size:13px; color:var(--muted);}}
+  .empty{{
+    background:#fff; border:1px dashed var(--line); border-radius:14px;
+    padding:22px; text-align:center; color:var(--muted); font-size:14px;
+  }}
+
+  .grid{{display:grid; grid-template-columns:repeat(auto-fill,minmax(320px,1fr)); gap:18px;}}
+  .card{{
+    background:var(--card); border:1px solid var(--line); border-radius:16px;
+    padding:18px 18px 16px; display:flex; flex-direction:column; gap:10px;
+    box-shadow:0 1px 3px rgba(20,30,60,.05); transition:.18s; position:relative; overflow:hidden;
+  }}
+  .card:hover{{transform:translateY(-3px); box-shadow:0 8px 22px rgba(20,30,60,.12);}}
+  .card .topaccent{{position:absolute; left:0; top:0; bottom:0; width:4px;}}
+  .card .num{{
+    position:absolute; top:14px; right:14px; font-size:12px; font-weight:700;
+    color:#fff; background:var(--hero1); width:26px; height:26px; border-radius:8px;
+    display:flex; align-items:center; justify-content:center;
+  }}
+  .card .title{{font-size:16px; font-weight:700; line-height:1.45; padding-right:34px; margin:0;}}
+  .card .chip{{
+    align-self:flex-start; font-size:12px; color:var(--ink);
+    background:var(--bg); border:1px solid var(--line); border-radius:999px; padding:3px 11px;
+  }}
+  .card .summary{{font-size:14px; color:#374151; margin:0; flex:1;}}
+  .card .link{{
+    align-self:flex-start; text-decoration:none; font-size:13.5px; font-weight:600;
+    color:var(--hero1); border:1px solid var(--hero1); border-radius:8px; padding:6px 12px; transition:.15s;
+  }}
+  .card .link:hover{{background:var(--hero1); color:#fff;}}
+
+  .foot{{
+    text-align:center; color:var(--muted); font-size:13px; border-top:1px solid var(--line);
+    padding-top:22px; margin-top:10px;
+  }}
+  .foot b{{color:var(--ink);}}
+  .foot a{{color:var(--hero1); text-decoration:none;}}
+
+  @media (max-width:560px){{
+    .hero h1{{font-size:24px;}}
+    .grid{{grid-template-columns:1fr;}}
+    .stat{{min-width:44%;}}
+  }}
+</style>
+</head>
+<body>
+  <header class="hero">
+    <div class="kicker">AI HOT · 晨报仪表盘</div>
+    <h1>AI HOT 日报 · {e(report_human)}</h1>
+    <div class="dateline">收录 {e(window_label)} 的 AI 动态（北京时间）</div>
+    <div class="total">本期共 <b>{total}</b> 条 AI 动态</div>
+    <div class="stats">{hero_stats}</div>
+  </header>
+
+  <nav class="nav">{nav}</nav>
+
+  <main class="wrap">{main}</main>
+
+  <footer class="foot">{footer}</footer>
+</body>
+</html>
+"""
+
+with open(OUT, "w", encoding="utf-8") as f:
+    f.write(HTML)
+
+print("WROTE:", OUT)
+print("report:", report_human, "| window:", window_label, "| total:", total)
+for s in sections:
+    print(f"  {s['label']}: {len(s['items'])}")
